SELECT COUNT(v.version_id) FROM doc_version v LEFT JOIN project_selection s ON v.selection_id = s.selection_id AND s.is_deleted = 0 LEFT JOIN sys_user stu ON v.student_id = stu.user_id AND stu.is_deleted = 0 LEFT JOIN project_topic pt ON s.topic_id = pt.topic_id AND pt.is_deleted = 0 WHERE v.is_deleted = 0
AND v.selection_id = #{req.selectionId}
AND s.campus_name LIKE CONCAT('%', #{req.campusName}, '%')
AND s.teacher_id = #{req.teacherId}
AND v.student_id = #{req.studentId}
AND s.academic_year LIKE CONCAT(#{req.academicYear}, '%')
AND v.stage_name LIKE CONCAT('%', #{req.stageName}, '%')
AND (stu.real_name LIKE CONCAT('%', #{req.keyword}, '%') OR stu.student_no LIKE CONCAT('%', #{req.keyword}, '%') OR pt.topic_name LIKE CONCAT('%', #{req.keyword}, '%') OR v.stage_name LIKE CONCAT('%', #{req.keyword}, '%'))

AND s.teacher_id = #{req.teacherId}
AND s.academic_year LIKE CONCAT(#{req.academicYear}, '%')
AND v.stage_name LIKE CONCAT('%', #{req.stageName}, '%')
AND (stu.real_name LIKE CONCAT('%', #{req.keyword}, '%') OR stu.student_no LIKE CONCAT('%', #{req.keyword}, '%') OR pt.topic_name LIKE CONCAT('%', #{req.keyword}, '%') OR v.stage_name LIKE CONCAT('%', #{req.keyword}, '%'))
ORDER BY v.create_time DESC LIMIT #{offset}, #{limit}
